import sqlite3

def check_user_permission(user_id, file_id):
    # Connect to the SQLite database
    conn = sqlite3.connect('document_management.db')
    cursor = conn.cursor()
    
    # Query the database to check user permission
    query = "SELECT has_read_access FROM permissions WHERE user_id=? AND file_id=?"
    cursor.execute(query, (user_id, file_id))
    result = cursor.fetchone()
    
    if result and result[0]:
        return True
    else:
        return False

def read_file_contents(file_path):
    # Check if the user has permission to read the file
    user_id = "current_user_id"  # Replace with actual user ID retrieval logic
    file_id = "file_id_from_path"  # Replace with actual file ID extraction logic
    
    if check_user_permission(user_id, file_id):
        try:
            with open(file_path, 'r') as file:
                contents = file.read()
                return contents
        except FileNotFoundError:
            return "File not found."
        except Exception as e:
            return f"Error reading file: {e}"
    else:
        return "Permission denied."

